  "attraction_manage.html": "function msg(t){alert(t)}\nfunction toggleNavGroup(el){el.closest('.nav-group').classList.toggle('open')}\nvar currentAttractionMode='new';\nvar currentEditingRow=null;\nvar ATTRACTION_STORAGE_KEY='avianext.attractions';\nfunction setMode(mode){currentAttractionMode=mode;document.getElementById('formSubmitButton').textContent=mode==='edit'?'변경내용저장':'신규등록'}\nfunction syncCategoryOptions(){\n  var names=[].map.call(document.querySelectorAll('.category-name'),function(el){return el.textContent.trim()});\n  ['filterCategory','formCategory'].forEach(function(id){var sel=document.getElementById(id),current=sel.value;sel.innerHTML=names.map(function(name){return '<option>'+name+'</option>'}).join('');if(names.indexOf(current)>=0)sel.value=current});\n}\nfunction selectCategory(item){document.querySelectorAll('.category-item').forEach(function(category){category.classList.remove('active')});item.classList.add('active');var name=item.querySelector('.category-name').textContent.trim();document.getElementById('filterCategory').value=name;document.getElementById('formCategory').value=name;resetAttractionForm()}\nfunction addCategory(){var input=document.getElementById('newCategoryName'),name=input.value.trim();if(!name){msg('카테고리명을 입력하세요.');return}var list=document.getElementById('categoryList');var item=document.createElement('div');item.className='category-item';item.dataset.count='0';item.onclick=function(){selectCategory(item)};item.innerHTML='<span class=\"category-name\">'+name+'</span><span class=\"category-count\">0개</span><button class=\"btn small red\" onclick=\"deleteCategory(event,this)\">삭제</button>';list.appendChild(item);input.value='';syncCategoryOptions();selectCategory(item)}\nfunction deleteCategory(event,btn){event.stopPropagation();var item=btn.closest('.category-item'),name=item.querySelector('.category-name').textContent.trim();if(!confirm(name+' 카테고리를 삭제할까요?'))return;item.remove();syncCategoryOptions();var first=document.querySelector('.category-item');if(first)selectCategory(first)}\nfunction filterAttractions(){msg('선택한 카테고리 기준으로 관광지 목록을 조회합니다.')}\nfunction editAttractionRow(btn){var row=btn.closest('tr');currentEditingRow=row;document.getElementById('formAttractionName').value=row.cells[0].textContent.trim();document.getElementById('formCategory').value=row.dataset.category||document.getElementById('filterCategory').value;document.getElementById('formDescription').value=row.dataset.desc||'';setMode('edit')}\nfunction resetAttractionForm(){currentEditingRow=null;document.getElementById('formCategory').value=document.getElementById('filterCategory').value;document.getElementById('formAttractionName').value='';document.getElementById('formDescription').value='';document.getElementById('formImages').value='';resetImagePreview();setMode('new')}\nfunction deleteAttractionRow(btn){var row=btn.closest('tr');if(confirm(row.cells[0].textContent.trim()+' 관광지를 삭제할까요?')){row.remove();if(currentEditingRow===row)resetAttractionForm();persistAttractions();msg('관광지가 삭제되었습니다.')}}\nfunction saveAttraction(){\n  var name=document.getElementById('formAttractionName').value.trim();\n  if(!name){msg('관광지명을 입력하세요.');return}\n  var category=document.getElementById('formCategory').value;\n  var desc=document.getElementById('formDescription').value.trim();\n  var row=currentAttractionMode==='edit'&&currentEditingRow?currentEditingRow:createAttractionRow();\n  row.dataset.category=category;\n  row.dataset.desc=desc;\n  row.querySelector('.attraction-link').textContent=name;\n  currentEditingRow=row;\n  persistAttractions();\n  msg(currentAttractionMode==='new'?'신규 관광지가 등록되었습니다.':'관광지 정보가 수정되었습니다.');\n  setMode('edit');\n}\nfunction openTourApiData(){msg('관광공사 API 연동 데이터 선택 화면을 연결할 예정입니다.')}\nfunction resetImagePreview(){document.getElementById('imagePreviewGrid').innerHTML='<span class=\"image-preview\">이미지1</span><span class=\"image-preview\">이미지2</span><span class=\"image-preview\">이미지3</span><span class=\"image-preview\">이미지4</span>'}\nfunction previewImages(input){\n  var files=[].slice.call(input.files||[]);\n  var grid=document.getElementById('imagePreviewGrid');\n  if(!files.length){resetImagePreview();return}\n  grid.innerHTML=files.map(function(file,index){return '<span class=\"image-preview\">'+(index+1)+'. '+file.name+'</span>'}).join('');\n}\nfunction createAttractionRow(){\n  var row=document.createElement('tr');\n  row.innerHTML='<td><button class=\"attraction-link\" onclick=\"editAttractionRow(this)\"></button></td><td class=\"center\"><button class=\"btn small red\" onclick=\"deleteAttractionRow(this)\">삭제</button></td>';\n  document.getElementById('attractionTable').appendChild(row);\n  return row;\n}\nfunction collectAttractions(){\n  return [].map.call(document.querySelectorAll('#attractionTable tr'),function(row){\n    return{name:row.cells[0].textContent.trim(),category:row.dataset.category||'',description:row.dataset.desc||''};\n  }).filter(function(item){return item.name});\n}\nfunction persistAttractions(){localStorage.setItem(ATTRACTION_STORAGE_KEY,JSON.stringify(collectAttractions()))}\nfunction loadAttractionsFromStorage(){\n  var saved=[];\n  try{saved=JSON.parse(localStorage.getItem(ATTRACTION_STORAGE_KEY)||'[]')}catch(e){saved=[]}\n  if(!Array.isArray(saved)||!saved.length){persistAttractions();return}\n  var table=document.getElementById('attractionTable');\n  table.innerHTML='';\n  saved.forEach(function(item){\n    var row=createAttractionRow();\n    row.dataset.category=item.category||'';\n    row.dataset.desc=item.description||'';\n    row.querySelector('.attraction-link').textContent=item.name||'';\n  });\n}\nloadAttractionsFromStorage();syncCategoryOptions();resetAttractionForm();",
